MERGE INTO CONSULTAS FIN USING (SELECT '002963SubActividadesTP' INFORME ,TO_CLOB(q'[SELECT COMPONENTES_ACTIVIDADES.ACTIVIDAD,
  COMPONENTES_ACTIVIDADES.NOMBREACTIVIDAD
  FROM BP_D_NOVEDADPROYECTO
  INNER JOIN COMPONENTES_ACTIVIDADES
 ON BP_D_NOVEDADPROYECTO.COMPANIA       = COMPONENTES_ACTIVIDADES.COMPANIA
AND BP_D_NOVEDADPROYECTO.PROYECTO       = COMPONENTES_ACTIVIDADES.CODIGOPROYECTO
AND BP_D_NOVEDADPROYECTO.COMPONENTE     = COMPONENTES_ACTIVIDADES.COMPONENTE
AND BP_D_NOVEDADPROYECTO.TIPOCOMPONENTE = COMPONENTES_ACTIVIDADES.TIPOCOMPONENTE
AND BP_D_NOVEDADPROYECTO.ACTIVIDAD      = COMPONENTES_ACTIVIDADES.ACTIVIDAD
WHERE BP_D_NOVEDADPROYECTO.COMPANIA = $P!{PR_COMPANIA}
  AND BP_D_NOVEDADPROYECTO.TIPOT    = '$P!{PR_TIPOT}'
  AND BP_D_NOVEDADPROYECTO.CLASET    = '$P!{PR_CLASET}'
  AND BP_D_NOVEDADPROYECTO.NOVEDAD  = $P!{PR_CONSECUTIVO}]') CONSULTA, 52 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);